-- Fixfy partner contract templates (Terms of Use, Self-Billing, Contractor Service Agreement)
-- Generated by master-trade-portal/scripts/generate-partner-contracts-migration.mts

ALTER TABLE public.contract_versions DROP CONSTRAINT IF EXISTS contract_versions_contract_type_check;
ALTER TABLE public.contract_versions
  ADD CONSTRAINT contract_versions_contract_type_check
  CHECK (contract_type IN (
    'terms_of_use',
    'self_bill_agreement',
    'contractor_service_agreement',
    'workforce_service_agreement',
    'workforce_employment_contract'
  ));

